const claudeResponses = $input.all();
const tripItems = $('Bouw request body').all();

const allDestinations = [];

claudeResponses.forEach(function(response, tripIndex) {
  const textBlock = (response.json.content || []).find(function(c) { return c.type === 'text' && c.text; });
  const responseText = textBlock ? textBlock.text : '';
  if (!responseText) return;
  const url = tripItems[tripIndex] ? tripItems[tripIndex].json.url || '' : '';
  const clean = responseText.replace(/```json|```/g, '').trim();

  let parsed;
  try {
    parsed = JSON.parse(clean);
  } catch(e) {
    return;
  }

  parsed.route.forEach(function(dest) {
    allDestinations.push({
      json: {
        order: dest.order,
        destination: dest.destination,
        destination_geocode: dest.destination_geocode || dest.destination,
        country: dest.country,
        days: dest.days,
        type: dest.type || 'destination',
        transport: dest.transport || 'unknown',
        bekendheid: dest.bekendheid || 1,
        day_label: dest.day_label || '',
        url: url
      }
    });
  });
});

return allDestinations;

const mapboxItems = $input.all();
const destinationItems = $('Bouw Mapbox URL').all();

function vindCountryCode(feature) {
  try {
    if (feature.place_type && feature.place_type.indexOf('country') !== -1) {
      return (feature.properties && feature.properties.short_code) ? feature.properties.short_code.toUpperCase() : null;
    }
    if (feature.context) {
      const c = feature.context.find(function(x) { return x.id && x.id.indexOf('country') === 0; });
      if (c && c.short_code) return c.short_code.toUpperCase();
    }
  } catch(e) {}
  return null;
}

return mapboxItems.map(function(item, i) {
  const dest = destinationItems[i] ? destinationItems[i].json : {};

  let features = [];
  try {
    const raw = item.json.data;
    const parsed = typeof raw === 'string' ? JSON.parse(raw) : raw;
    features = parsed.features || [];
  } catch(e) {}

  if (!features || features.length === 0) {
    return {
      json: {
        order: dest.order,
        destination: dest.destination,
        destination_geocode: dest.destination_geocode || dest.destination,
        country: dest.country,
        days: dest.days,
        type: dest.type || 'destination',
        transport: dest.transport || 'car',
        bekendheid: dest.bekendheid || 1,
        day_label: dest.day_label || '',
        url: dest.url || '',
        latitude: null,
        longitude: null,
        place_name: null,
        country_code: null,
        error: 'Geen coordinaten gevonden'
      }
    };
  }

  return {
    json: {
      order: dest.order,
      destination: dest.destination,
      destination_geocode: dest.destination_geocode || dest.destination,
      country: dest.country,
      days: dest.days,
      type: dest.type || 'destination',
      transport: dest.transport || 'car',
      bekendheid: dest.bekendheid || 1,
      day_label: dest.day_label || '',
      url: dest.url || '',
      latitude: features[0].center[1],
      longitude: features[0].center[0],
      place_name: features[0].place_name,
      country_code: vindCountryCode(features[0])
    }
  };
});

const allItems = $input.all();

const tripMap = {};
allItems.forEach(function(item) {
  const url = item.json.url || '';
  if (!tripMap[url]) {
    tripMap[url] = [];
  }
  tripMap[url].push({
    order: item.json.order,
    destination: item.json.destination,
    destination_geocode: item.json.destination_geocode || item.json.destination,
    country: item.json.country,
    country_code: item.json.country_code || null,
    days: item.json.days,
    type: item.json.type || 'destination',
    transport: item.json.transport || 'unknown',
    bekendheid: item.json.bekendheid || 1,
    url: item.json.url || '',
    latitude: item.json.latitude,
    longitude: item.json.longitude,
    place_name: item.json.place_name
  });
});

return Object.keys(tripMap).map(function(url) {
  const route = tripMap[url].sort(function(a, b) { return a.order - b.order; });
  return {
    json: {
      URL: url,
      route: route,
      total_destinations: route.length,
      generated_at: new Date().toISOString()
    }
  };
});

const items = $input.all();
return items.map(function(item, index) {
  const destinationGeocode = item.json.destination_geocode || item.json.destination;
  const country = item.json.country;
  const searchText = encodeURIComponent(destinationGeocode + ', ' + country);
  const mapboxUrl = 'https://api.mapbox.com/geocoding/v5/mapbox.places/' + searchText + '.json';
  return {
    json: {
      _index: index,
      order: item.json.order,
      destination: item.json.destination,
      destination_geocode: destinationGeocode,
      country: country,
      days: item.json.days,
      type: item.json.type || 'destination',
      transport: item.json.transport || 'car',
      bekendheid: item.json.bekendheid || 1,
      url: item.json.url || '',
      mapboxUrl: mapboxUrl
    }
  };
});

const items = $input.all();

const landNL = {
  'thailand': 'Thailand', 'laos': 'Laos', 'cambodia': 'Cambodja', 'vietnam': 'Vietnam',
  'myanmar': 'Myanmar', 'malaysia': 'Maleisi\u00eb', 'indonesia': 'Indonesi\u00eb', 'singapore': 'Singapore',
  'philippines': 'Filipijnen', 'japan': 'Japan', 'china': 'China', 'india': 'India', 'nepal': 'Nepal',
  'sri lanka': 'Sri Lanka', 'south africa': 'Zuid-Afrika', 'eswatini': 'eSwatini', 'lesotho': 'Lesotho',
  'namibia': 'Namibi\u00eb', 'botswana': 'Botswana', 'zimbabwe': 'Zimbabwe', 'zambia': 'Zambia',
  'tanzania': 'Tanzania', 'kenya': 'Kenia', 'mozambique': 'Mozambique', 'morocco': 'Marokko',
  'egypt': 'Egypte', 'jordan': 'Jordani\u00eb', 'greece': 'Griekenland', 'italy': 'Itali\u00eb',
  'spain': 'Spanje', 'portugal': 'Portugal', 'france': 'Frankrijk', 'croatia': 'Kroati\u00eb',
  'peru': 'Peru', 'argentina': 'Argentini\u00eb', 'chile': 'Chili', 'brazil': 'Brazili\u00eb',
  'bolivia': 'Bolivia', 'ecuador': 'Ecuador', 'colombia': 'Colombia', 'costa rica': 'Costa Rica',
  'mexico': 'Mexico', 'cuba': 'Cuba', 'united states': 'Verenigde Staten', 'canada': 'Canada',
  'australia': 'Australi\u00eb', 'new zealand': 'Nieuw-Zeeland', 'iceland': 'IJsland',
  'norway': 'Noorwegen', 'sweden': 'Zweden', 'turkey': 'Turkije', 'united kingdom': 'Verenigd Koninkrijk',
  'ireland': 'Ierland', 'germany': 'Duitsland', 'austria': 'Oostenrijk', 'switzerland': 'Zwitserland'
};
function naarNL(land) {
  const key = (land || '').toLowerCase().trim();
  return landNL[key] || land;
}

return items.map(function(item) {
  const route = item.json.route;
  const url = item.json.URL;

  const validStops = route
    .filter(function(s) { return s.latitude !== null && s.longitude !== null && s.latitude !== undefined && s.longitude !== undefined; })
    .sort(function(a, b) { return a.order - b.order; });

  const stopNamenSet = {};
  validStops.forEach(function(s) { stopNamenSet[(s.destination || '').toLowerCase().trim()] = true; });

  const landGezien = {};
  validStops.forEach(function(s) {
    const land = (s.country || '').trim();
    const landLower = land.toLowerCase();
    if (land && !landGezien[landLower] && !stopNamenSet[landLower]) {
      landGezien[landLower] = true;
      s._toonLand = naarNL(land);
    } else {
      s._toonLand = '';
      if (land) landGezien[landLower] = true;
    }
  });

  const legenda = validStops.map(function(stop) {
    const dagLabel = stop.day_label || (stop.type === 'transit' ? 'tussenstop' : stop.type === 'arrival' ? 'aankomst/vertrek' : '');
    return stop.order + '. ' + stop.destination + (dagLabel ? ' - ' + dagLabel : '');
  }).join('\n');

  const eersteOrder = validStops.length ? validStops[0].order : null;
  const laatsteOrder = validStops.length ? validStops[validStops.length - 1].order : null;

  const markersJson = JSON.stringify(validStops.map(function(s) {
    return {
      order: s.order, destination: s.destination, country: s.country || '', toonLand: s._toonLand || '', days: s.days,
      lng: s.longitude, lat: s.latitude, type: s.type || 'destination',
      transport: s.transport || 'car', bekendheid: s.bekendheid || 1, day_label: s.day_label || '',
      isStart: s.order === eersteOrder, isEind: s.order === laatsteOrder
    };
  }));

  const reisNaam = url.split('/').filter(Boolean).pop() || 'rondreis';
  const avgLng = validStops.reduce(function(sum, s) { return sum + s.longitude; }, 0) / validStops.length;
  const avgLat = validStops.reduce(function(sum, s) { return sum + s.latitude; }, 0) / validStops.length;

  const segmentsJson = JSON.stringify(validStops.slice(1).map(function(s, i) {
    return { from: [validStops[i].longitude, validStops[i].latitude], to: [s.longitude, s.latitude], transport: s.transport || 'car' };
  }));

  const gezien = {};
  const tripCountries = [];
  validStops.forEach(function(s) {
    if (s.country_code && !gezien[s.country_code]) { gezien[s.country_code] = true; tripCountries.push(s.country_code); }
  });
  const tripCountriesJson = JSON.stringify(tripCountries);

  const html = `<!DOCTYPE html>
<html lang="nl">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Routekaart - ${reisNaam}</title>
<script src="https://api.mapbox.com/mapbox-gl-js/v3.3.0/mapbox-gl.js"></script>
<link href="https://api.mapbox.com/mapbox-gl-js/v3.3.0/mapbox-gl.css" rel="stylesheet">
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }
  body { font-family: -apple-system, BlinkMacSystemFont, sans-serif; background: #F9FBFB; }
  #map { width: 100%; height: 65vh; min-height: 420px; }
  .land-label-marker { pointer-events: none; }
  .stop-land { font-size: 15px; font-weight: 700; font-style: italic; color: #FFFFFF; text-transform: uppercase; letter-spacing: 0.5px; white-space: nowrap; text-shadow: 0 1px 2px rgba(40,48,56,0.78); }
  #legenda { padding: 16px 20px; background: #F9FBFB; border-top: 1px solid #ABC6CB; }
  #legenda h3 { font-size: 15px; font-weight: 600; margin-bottom: 10px; color: #3B4651; }
  .legenda-uitleg { display: flex; gap: 16px; margin-bottom: 12px; font-size: 11px; color: #3B4651; flex-wrap: wrap; }
  .legenda-uitleg span { display: inline-flex; align-items: center; gap: 5px; }
  .mini-ring { width: 11px; height: 11px; border-radius: 50%; background: #F9FBFB; border: 2px solid #3B4651; display: inline-block; }
  .legenda-item { display: flex; align-items: center; gap: 10px; padding: 6px 0; border-bottom: 1px solid #B9D9E0; font-size: 13px; color: #3B4651; }
  .legenda-item:last-child { border-bottom: none; }
  .legenda-dag { color: #3B4651; font-size: 12px; font-weight: 600; min-width: 72px; flex-shrink: 0; }
  .legenda-transport { display: inline-flex; align-items: center; margin-left: 2px; }
  .mapboxgl-popup-content { padding: 10px 14px; border-radius: 8px; font-family: -apple-system, BlinkMacSystemFont, sans-serif; box-shadow: 0 2px 8px rgba(59,70,81,0.2); background: #F9FBFB; }
  .popup-title { font-weight: 600; font-size: 13px; margin-bottom: 3px; color: #3B4651; }
  .popup-dagen { color: #3B4651; font-size: 12px; }
  .popup-transport { font-size: 11px; color: #3B4651; margin-top: 2px; display: flex; align-items: center; gap: 4px; }
</style>
</head>
<body>
<div id="map"></div>
<div id="legenda">
  <h3>Route</h3>
  <div class="legenda-uitleg">
    <span><span class="mini-ring"></span> Start- en eindpunt</span>
  </div>
  <div id="legenda-items"></div>
</div>
<script>
mapboxgl.accessToken = new URLSearchParams(window.location.search).get('t') || '';

const stops = ${markersJson};
const segments = ${segmentsJson};
const tripCountries = ${tripCountriesJson};

const KLEUR_LICHT = '#F9FBFB';
const KLEUR_BLAUW = '#B9D9E0';
const KLEUR_DONKER = '#3B4651';
const KLEUR_GRIJS = '#ABC6CB';

const transportConfig = {
  flight:  { dash: [2, 2], width: 2, label: 'Vlucht',     svg: 'M21,16v-2l-8-5V3.5C13,2.67,12.33,2,11.5,2S10,2.67,10,3.5V9l-8,5v2l8-2.5V19l-2,1.5V22l3.5-1l3.5,1v-1.5L13,19v-5.5L21,16z' },
  ferry:   { dash: [4, 2], width: 2, label: 'Ferry/boot', svg: 'M20,21c-1.39,0-2.78-0.47-4-1.32c-2.44,1.71-5.56,1.71-8,0C6.78,20.53,5.39,21,4,21H2v2h2c1.38,0,2.74-0.35,4-0.99c2.52,1.29,5.48,1.29,8,0c1.26,0.65,2.62,0.99,4,0.99h2v-2H20z M3.95,19H4c1.6,0,3.02-0.88,4-2c0.98,1.12,2.4,2,4,2s3.02-0.88,4-2c0.98,1.12,2.4,2,4,2h0.05l1.89-6.68c0.08-0.26,0.06-0.54-0.06-0.78s-0.34-0.42-0.6-0.5L20,10.62V6c0-1.1-0.9-2-2-2h-3V1H9v3H6C4.9,4,4,4.9,4,6v4.62l-1.29,0.42c-0.26,0.08-0.48,0.26-0.6,0.5s-0.15,0.52-0.06,0.78L3.95,19z M6,6h12v3.97L12,8L6,9.97V6z' },
  train:   { dash: [6, 2], width: 3, label: 'Trein',      svg: 'M12,2c-4.42,0-8,0.5-8,4v9.5C4,17.43,5.57,19,7.5,19L6,20.5V21h12v-0.5L16.5,19c1.93,0,3.5-1.57,3.5-3.5V6C20,2.5,16.42,2,12,2z M7.5,17C6.67,17,6,16.33,6,15.5S6.67,14,7.5,14S9,14.67,9,15.5S8.33,17,7.5,17z M11,11H6V6h5V11z M16.5,17c-0.83,0-1.5-0.67-1.5-1.5s0.67-1.5,1.5-1.5s1.5,0.67,1.5,1.5S17.33,17,16.5,17z M18,11h-5V6h5V11z' },
  cruise:  { dash: [8, 3], width: 3, label: 'Cruise',     svg: 'M20,21c-1.39,0-2.78-0.47-4-1.32c-2.44,1.71-5.56,1.71-8,0C6.78,20.53,5.39,21,4,21H2v2h2c1.38,0,2.74-0.35,4-0.99c2.52,1.29,5.48,1.29,8,0c1.26,0.65,2.62,0.99,4,0.99h2v-2H20z M3.95,19H4c1.6,0,3.02-0.88,4-2c0.98,1.12,2.4,2,4,2s3.02-0.88,4-2c0.98,1.12,2.4,2,4,2h0.05l1.89-6.68c0.08-0.26,0.06-0.54-0.06-0.78s-0.34-0.42-0.6-0.5L20,10.62V6c0-1.1-0.9-2-2-2h-3V1H9v3H6C4.9,4,4,4.9,4,6v4.62l-1.29,0.42c-0.26,0.08-0.48,0.26-0.6,0.5s-0.15,0.52-0.06,0.78L3.95,19z M6,6h12v3.97L12,8L6,9.97V6z' },
  walk:    { dash: [2, 3], width: 2, label: 'Wandelen',   svg: 'M13.5,5.5c1.1,0,2-0.9,2-2s-0.9-2-2-2s-2,0.9-2,2S12.4,5.5,13.5,5.5z M9.8,8.9L7,23h2.1l1.8-8l2.1,2v6h2v-7.5l-2.1-2l0.6-3C12.8,11,14.8,12,17,12v-2c-1.9,0-3.5-1-4.3-2.4l-1-1.6C11.3,5.4,10.7,5,10,5C9.7,5,9.5,5.1,9.2,5.1L4,7.3V13h2V8.6l1.8-0.7' },
  car:     { dash: [],     width: 3, label: 'Auto',       svg: '' },
  unknown: { dash: [],     width: 2, label: '',           svg: '' }
};

function svgIcon(pad, maat, halo) {
  if (!pad) return '';
  var h = halo ? '<path d="' + pad + '" fill="none" stroke="' + KLEUR_LICHT + '" stroke-width="3.5" stroke-linejoin="round" stroke-linecap="round"/>' : '';
  return '<svg xmlns="http://www.w3.org/2000/svg" width="' + maat + '" height="' + maat + '" viewBox="0 0 24 24" fill="' + KLEUR_DONKER + '">' + h + '<path d="' + pad + '"/></svg>';
}

function boogCoords(from, to, transport, punten) {
  punten = punten || 40;
  var useBoog = (transport === 'flight' || transport === 'ferry' || transport === 'cruise');
  if (!useBoog) {
    var rechte = [];
    for (var k = 0; k <= punten; k++) {
      var tt = k / punten;
      rechte.push([from[0] + (to[0] - from[0]) * tt, from[1] + (to[1] - from[1]) * tt]);
    }
    return rechte;
  }
  var dx = to[0] - from[0]; var dy = to[1] - from[1];
  var dist = Math.sqrt(dx*dx + dy*dy);
  var boogHoogte = dist * (transport === 'flight' ? 0.40 : 0.20);
  var mx = (from[0] + to[0]) / 2; var my = (from[1] + to[1]) / 2;
  var nx = -dy / dist; var ny = dx / dist;
  var ctrl = [mx + nx * boogHoogte, my + ny * boogHoogte];
  var coords = [];
  for (var i = 0; i <= punten; i++) {
    var t = i / punten;
    var x = (1-t)*(1-t)*from[0] + 2*(1-t)*t*ctrl[0] + t*t*to[0];
    var y = (1-t)*(1-t)*from[1] + 2*(1-t)*t*ctrl[1] + t*t*to[1];
    coords.push([x, y]);
  }
  return coords;
}

const landenFilter = ['all',
  ['any', ['==', ['get', 'worldview'], 'all'], ['in', 'US', ['get', 'worldview']]],
  ['in', ['get', 'iso_3166_1'], ['literal', tripCountries]]
];

const map = new mapboxgl.Map({
  container: 'map',
  style: {
    version: 8,
    glyphs: 'mapbox://fonts/mapbox/{fontstack}/{range}.pbf',
    sources: { landen: { type: 'vector', url: 'mapbox://mapbox.country-boundaries-v1' } },
    layers: [
      { id: 'achtergrond', type: 'background', paint: { 'background-color': KLEUR_LICHT } },
      { id: 'reisland-vlak', type: 'fill', source: 'landen', 'source-layer': 'country_boundaries', filter: landenFilter, paint: { 'fill-color': KLEUR_BLAUW } },
      { id: 'reisland-grens', type: 'line', source: 'landen', 'source-layer': 'country_boundaries', filter: landenFilter, paint: { 'line-color': KLEUR_GRIJS, 'line-width': 1.5 } }
    ]
  },
  center: [${avgLng}, ${avgLat}],
  zoom: 4
});

map.addControl(new mapboxgl.NavigationControl(), 'top-right');
map.addControl(new mapboxgl.FullscreenControl(), 'top-right');

map.on('load', function() {

  var transportMarkers = [];

  segments.forEach(function(seg, idx) {
    var cfg = transportConfig[seg.transport] || transportConfig.unknown;
    var coords = boogCoords(seg.from, seg.to, seg.transport);
    var sourceId = 'route-' + idx; var layerId = 'route-line-' + idx;
    map.addSource(sourceId, { type: 'geojson', data: { type: 'Feature', geometry: { type: 'LineString', coordinates: coords } } });
    var paint = { 'line-color': KLEUR_DONKER, 'line-width': cfg.width, 'line-opacity': 0.9 };
    if (cfg.dash && cfg.dash.length > 0) { paint['line-dasharray'] = cfg.dash; }
    map.addLayer({ id: layerId, type: 'line', source: sourceId, layout: { 'line-join': 'round', 'line-cap': 'round' }, paint: paint });

    if (cfg.svg) {
      var iconPos = coords[Math.floor(coords.length * 0.5)];
      var iconEl = document.createElement('div');
      iconEl.style.cssText = 'cursor:default;user-select:none;line-height:0;';
      var innerEl = document.createElement('div');
      innerEl.style.cssText = 'line-height:0;';
      if (seg.transport === 'flight') {
        var fLatRad = ((seg.from[1] + seg.to[1]) / 2) * Math.PI / 180;
        var fdx = (seg.to[0] - seg.from[0]) * Math.cos(fLatRad);
        var fdy = -(seg.to[1] - seg.from[1]);
        var fHoek = Math.atan2(fdy, fdx) * 180 / Math.PI + 90;
        innerEl.style.transform = 'rotate(' + fHoek + 'deg)';
      }
      innerEl.innerHTML = svgIcon(cfg.svg, 16, true);
      iconEl.appendChild(innerEl);
      new mapboxgl.Marker({ element: iconEl, anchor: 'center' }).setLngLat(iconPos).addTo(map);
      transportMarkers.push({ el: iconEl, lngLat: iconPos });
    }
  });

  var perLocatie = {};
  stops.forEach(function(stop) {
    var key = stop.lng.toFixed(5) + ',' + stop.lat.toFixed(5);
    if (!perLocatie[key]) perLocatie[key] = [];
    perLocatie[key].push(stop);
  });

  var TOON_LANDNAMEN = false;

  function locKey(s){ return s.lng.toFixed(5) + ',' + s.lat.toFixed(5); }
  var lijnRichtingen = {};
  for (var li = 0; li < stops.length; li++) {
    var ls = stops[li];
    var lk = locKey(ls);
    if (!lijnRichtingen[lk]) lijnRichtingen[lk] = [];
    var buren = [];
    if (li > 0) buren.push(stops[li - 1]);
    if (li < stops.length - 1) buren.push(stops[li + 1]);
    buren.forEach(function(b) {
      var latRad = ls.lat * Math.PI / 180;
      var gx = (b.lng - ls.lng) * Math.cos(latRad);
      var gy = (b.lat - ls.lat);
      var len = Math.sqrt(gx * gx + gy * gy);
      if (len > 1e-9) lijnRichtingen[lk].push([gx / len, gy / len]);
    });
  }

  var KANDIDATEN = [
    { dir: [1, 0],   anchor: 'left',         off: [1.15, 0] },
    { dir: [-1, 0],  anchor: 'right',        off: [-1.15, 0] },
    { dir: [0, 1],   anchor: 'bottom',       off: [0, -1.15] },
